/* ---------------------------------------------------------------------------
 * useChat — suite 19/P03
 * Client-side state machine for the chat conversation. Owns the message list,
 * issues SSE requests against /api/chat, progressively appends streamed
 * tokens to an assistant placeholder, and surfaces error / rate-limit state
 * so the UI can render a retry affordance.
 * --------------------------------------------------------------------------- */

"use client";

import { useCallback, useRef, useState } from "react";

import {
  type ChatMetaPayload,
  type Citation,
  type ClientChatMessage,
} from "@/lib/llm/chatTypes";
import { streamReader } from "@/lib/llm/streamReader";

export type ChatStatus = "idle" | "streaming" | "error";

export type UseChatReturn = {
  messages: ClientChatMessage[];
  status: ChatStatus;
  submit: (text: string) => Promise<void>;
  retry: () => Promise<void>;
  clear: () => void;
  stopStreaming: () => void;
  lastError?: string;
};

let _idCounter = 0;
function nextId(prefix: string): string {
  _idCounter += 1;
  return `${prefix}-${Date.now().toString(36)}-${_idCounter}`;
}

export function useChat(): UseChatReturn {
  const [messages, setMessages] = useState<ClientChatMessage[]>([]);
  const [status, setStatus] = useState<ChatStatus>("idle");
  const [lastError, setLastError] = useState<string | undefined>(undefined);

  const abortRef = useRef<AbortController | null>(null);
  const lastUserTextRef = useRef<string | null>(null);

  const updateMessage = useCallback(
    (id: string, patch: Partial<ClientChatMessage>) => {
      setMessages((prev) =>
        prev.map((m) => (m.id === id ? { ...m, ...patch } : m)),
      );
    },
    [],
  );

  const appendToken = useCallback((id: string, token: string) => {
    setMessages((prev) =>
      prev.map((m) =>
        m.id === id ? { ...m, content: m.content + token } : m,
      ),
    );
  }, []);

  const runStream = useCallback(
    async (
      historyForServer: { role: "user" | "assistant"; content: string }[],
      placeholderId: string,
    ) => {
      setStatus("streaming");
      setLastError(undefined);

      const controller = new AbortController();
      abortRef.current = controller;

      let response: Response;
      try {
        response = await fetch("/api/chat", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ messages: historyForServer }),
          signal: controller.signal,
        });
      } catch (err) {
        abortRef.current = null;
        if (controller.signal.aborted) {
          updateMessage(placeholderId, { status: "complete" });
          setStatus("idle");
          return;
        }
        const detail = err instanceof Error ? err.message : "network error";
        updateMessage(placeholderId, { status: "error" });
        setLastError(detail);
        setStatus("error");
        return;
      }

      if (!response.ok) {
        let detail = `request failed (${response.status})`;
        try {
          const body = (await response.json()) as {
            error?: string;
            detail?: string;
          };
          if (typeof body.detail === "string" && body.detail) {
            detail = body.detail;
          } else if (typeof body.error === "string" && body.error) {
            detail = body.error;
          }
        } catch {
          // body was not JSON; use the default detail.
        }
        if (response.status === 429) {
          detail = `Rate limited — ${detail}. Please wait a moment and retry.`;
        }
        abortRef.current = null;
        updateMessage(placeholderId, { status: "error" });
        setLastError(detail);
        setStatus("error");
        return;
      }

      try {
        for await (const frame of streamReader(response)) {
          if (frame.event === "token") {
            let token: string;
            try {
              token = JSON.parse(frame.data) as string;
            } catch {
              token = frame.data;
            }
            if (typeof token === "string" && token.length > 0) {
              appendToken(placeholderId, token);
            }
          } else if (frame.event === "meta") {
            try {
              const meta = JSON.parse(frame.data) as ChatMetaPayload;
              const citations: Citation[] = (meta.citations ?? []).map(
                (c) => ({
                  id: c.id,
                  chunkId: c.chunkId,
                  snippet: c.snippet,
                }),
              );
              updateMessage(placeholderId, { citations });
            } catch {
              // malformed meta — ignore.
            }
          } else if (frame.event === "error") {
            let detail = "stream error";
            try {
              const body = JSON.parse(frame.data) as { detail?: string };
              if (typeof body?.detail === "string" && body.detail) {
                detail = body.detail;
              }
            } catch {
              // ignore
            }
            abortRef.current = null;
            updateMessage(placeholderId, { status: "error" });
            setLastError(detail);
            setStatus("error");
            return;
          } else if (frame.event === "done") {
            break;
          }
        }

        updateMessage(placeholderId, { status: "complete" });
        setStatus("idle");
      } catch (err) {
        if (controller.signal.aborted) {
          updateMessage(placeholderId, { status: "complete" });
          setStatus("idle");
          return;
        }
        const detail = err instanceof Error ? err.message : "stream failed";
        updateMessage(placeholderId, { status: "error" });
        setLastError(detail);
        setStatus("error");
      } finally {
        abortRef.current = null;
      }
    },
    [appendToken, updateMessage],
  );

  const submit = useCallback(
    async (text: string) => {
      const trimmed = text.trim();
      if (!trimmed) return;
      if (abortRef.current) return; // already streaming

      const now = Date.now();
      const userMsg: ClientChatMessage = {
        id: nextId("u"),
        role: "user",
        content: trimmed,
        status: "complete",
        createdAt: now,
      };
      const placeholder: ClientChatMessage = {
        id: nextId("a"),
        role: "assistant",
        content: "",
        status: "streaming",
        createdAt: now + 1,
      };

      lastUserTextRef.current = trimmed;

      // Capture the latest message list synchronously so the request payload
      // includes the just-pushed user message — useState updates don't flush
      // before we read state.
      const historyForServer = (() => {
        const prior = messagesRefSnapshot.current
          .filter((m) => m.status === "complete")
          .map((m) => ({ role: m.role, content: m.content }));
        prior.push({ role: "user", content: trimmed });
        return prior;
      })();

      setMessages((prev) => [...prev, userMsg, placeholder]);

      await runStream(historyForServer, placeholder.id);
    },
    [runStream],
  );

  const retry = useCallback(async () => {
    if (abortRef.current) return;
    const lastText = lastUserTextRef.current;
    if (!lastText) return;

    // Drop any trailing errored assistant placeholder so we don't leave
    // stale state in the visible history. The user message stays.
    let placeholderId = "";
    setMessages((prev) => {
      const next = [...prev];
      while (
        next.length > 0 &&
        next[next.length - 1].role === "assistant" &&
        next[next.length - 1].status !== "complete"
      ) {
        next.pop();
      }
      const newPlaceholder: ClientChatMessage = {
        id: nextId("a"),
        role: "assistant",
        content: "",
        status: "streaming",
        createdAt: Date.now(),
      };
      placeholderId = newPlaceholder.id;
      next.push(newPlaceholder);
      return next;
    });

    // Build the server payload from completed messages plus the retried text.
    const historyForServer = messagesRefSnapshot.current
      .filter((m) => m.status === "complete")
      .map((m) => ({ role: m.role, content: m.content }));
    if (
      historyForServer.length === 0 ||
      historyForServer[historyForServer.length - 1].role !== "user" ||
      historyForServer[historyForServer.length - 1].content !== lastText
    ) {
      // Defensive: if the user message is missing from history, append it.
      historyForServer.push({ role: "user", content: lastText });
    }

    await runStream(historyForServer, placeholderId);
  }, [runStream]);

  const clear = useCallback(() => {
    if (abortRef.current) {
      abortRef.current.abort();
      abortRef.current = null;
    }
    setMessages([]);
    setStatus("idle");
    setLastError(undefined);
    lastUserTextRef.current = null;
  }, []);

  const stopStreaming = useCallback(() => {
    const ctrl = abortRef.current;
    if (!ctrl) return;
    ctrl.abort();
    abortRef.current = null;
    // The streaming loop catches the abort and finalizes the placeholder.
    // We pre-emptively flip status here so callers see the change without
    // waiting for the microtask flush.
    setStatus("idle");
  }, []);

  // Keep a synchronous mirror of `messages` so submit/retry can read the
  // latest list without waiting for state to settle.
  const messagesRefSnapshot = useRef<ClientChatMessage[]>([]);
  messagesRefSnapshot.current = messages;

  return {
    messages,
    status,
    submit,
    retry,
    clear,
    stopStreaming,
    lastError,
  };
}

